  // ─── BookFinder URL ───────────────────────────────────────────────────────
  function bookFinderUrl(title, author) {
    return 'https://www.bookfinder.com/search/?ac=sl&st=sl&qi=0' +
      '&author=' + encodeURIComponent(author) +
      '&title='  + encodeURIComponent(title);
  }

  // ─── Slug generator ──────────────────────────────────────────────────────
  function slugify(title) {
    return title.toLowerCase()
      .replace(/[^a-z0-9\s-]/g, '')
      .replace(/\s+/g, '-')
      .replace(/-+/g, '-')
      .trim();
  }

